SELECT AVG(population) AS average_population, COUNT(country_id) AS number_of_countries
FROM countries
WHERE region = 'North America';

SELECT category, COUNT(*) AS indicator_count
FROM indicators
GROUP BY category;

SELECT indicator_name
FROM indicators
WHERE indicator_type = 'development';

SELECT value
FROM data_points
WHERE data_id = 1;

SELECT value
FROM data_points
WHERE year = 2020;
